from typing import List

class Solution:
    def solve(self, nums: List[int]) -> bool:

        swapped = True
        while swapped:
            swapped = False

            for i in range(len(nums) - 1):
                if nums[i] > nums[i + 1]:
                    nums[i], nums[i + 1] = nums[i + 1], nums[i]
                    swapped = True

        return swapped

def main():
    n = int(input())
    nums = list(map(int, input().split(' ')))

    solution = Solution()
    print(solution.solve(nums))

main()

