#include <iostream>
#include <vector>
using namespace std;

bool solve(vector<int>& nums) {
    bool swapped = true;
    while (swapped) {
        swapped = false;

        for (int i = 0; i < nums.size() - 1; i++) {
            if (nums[i] > nums[i + 1]) {
                int temp = nums[i];
                nums[i] = nums[i + 1];
                nums[i + 1] = temp;
                swapped = true;
            }
        }
    }

    return swapped;
}

int main() {
    int n;
    cin >> n;

    for (int i = 0; i < n; i++) {
        int num;
        cin >> num;
        nums.push_back(num);
    }

    bool result = solve(nums);
    cout << (result ? "true" : "false") << endl;

    return 0;
}
